#include <stdbool.h>

typedef struct {
    bool locked;
} Lock;

// TestAndSet atomic instruction
bool TestAndSet(bool *target) {
    bool temp = *target;
    *target = true;
    return temp;
}

// Using TestAndSet for mutual exclusion
void lock_acquire(Lock *lock) {
    while (TestAndSet(&lock->locked)) {
        // busy wait - lock is busy
    }
    // lock acquired - entered critical section
}

void lock_release(Lock *lock) {
    lock->locked = false;
}

// Example usage in critical section
void critical_section_example(Lock *lock) {
    lock_acquire(lock);
    // Critical section - access shared resources
    // ...
    lock_release(lock);
    // Remainder section
}

public class CriticalSectionExample {
    private int sharedCounter = 0;
    private final Object lock = new Object();

    // Method demonstrating critical section
    public void incrementCounter() {
        // Entry section
        synchronized(lock) {
            // Critical section - only one thread here
            sharedCounter++;
            System.out.println("Counter: " + sharedCounter + 
                " by " + Thread.currentThread().getName());
        }
        // Exit section - lock automatically released
    }

    // Alternative using synchronized method
    public synchronized void safeIncrement() {
        // Entire method is critical section
        sharedCounter++;
    }

    // Main for testing
    public static void main(String[] args) {
        CriticalSectionExample example = new CriticalSectionExample();

        // Create multiple threads accessing shared resource
        for (int i = 0; i < 5; i++) {
            new Thread(() -> {
                for (int j = 0; j < 10; j++) {
                    example.incrementCounter();
                }
            }, "Thread-" + i).start();
        }
    }
}
